import React, { useState, useEffect } from 'react';
import {
  Paper,
  Typography,
  Box,
  Skeleton,
  useTheme,
  Divider
} from '@mui/material';
import {
  ShowChart,
  Timeline,
  TrendingUp
} from '@mui/icons-material';
import dashboardService from '../../services/dashboardService';

const ConsolidatedStatsCard = ({ hideValues = false }) => {
  const theme = useTheme();
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);
  const [openPositions, setOpenPositions] = useState([]);

  // Carregar dados do dashboard
  useEffect(() => {
    const loadStats = async (showLoading = true) => {
      try {
        if (showLoading) {
          setLoading(true);
        }
        const [statsResponse, openPositionsResponse] = await Promise.all([
          dashboardService.getUserStats(),
          dashboardService.getOpenPositions()
        ]);

        const statsData = statsResponse.data || statsResponse;
        const openPositionsData = openPositionsResponse.data || [];

        setOpenPositions(openPositionsData);
        setStats(statsData);
      } catch (error) {
        console.error('Erro ao carregar estatísticas:', error);
        setStats(null);
      } finally {
        if (showLoading) {
          setLoading(false);
        }
      }
    };

    loadStats(true);

    // Timer para atualização automática a cada 30 segundos
    const interval = setInterval(() => {
      loadStats(false);
    }, 30000);

    return () => clearInterval(interval);
  }, []);

  const formatCurrency = (value) => {
    if (hideValues) return '$***';
    if (value === null || value === undefined) return '$0.00';
    const numValue = parseFloat(value);

    if (Math.abs(numValue) < 0.001 && numValue !== 0) {
      return `$${numValue.toFixed(8)}`;
    }
    if (Math.abs(numValue) < 0.1 && numValue !== 0) {
      return `$${numValue.toFixed(6)}`;
    }
    if (Math.abs(numValue) < 1) {
      return `$${numValue.toFixed(4)}`;
    }
    return `$${numValue.toFixed(2)}`;
  };

  const formatPercentage = (value) => {
    if (hideValues) return '***%';
    if (value === null || value === undefined) return '0%';

    if (Math.abs(value) < 0.01 && value !== 0) {
      return `${value >= 0 ? '+' : ''}${value.toFixed(6)}%`;
    }
    if (Math.abs(value) < 1) {
      return `${value >= 0 ? '+' : ''}${value.toFixed(4)}%`;
    }
    return `${value >= 0 ? '+' : ''}${value.toFixed(2)}%`;
  };

  const getColorByValue = (value) => {
    if (value > 0) return theme.palette.success.main;
    if (value < 0) return theme.palette.error.main;
    return theme.palette.text.secondary;
  };

  // Calcular ROE das posições abertas
  const calculateOpenROE = () => {
    if (!openPositions || openPositions.length === 0) return 0;

    let totalROE = 0;

    openPositions.forEach(position => {
      let positionROE = 0;

      if (position.roe !== undefined && position.roe !== null) {
        positionROE = parseFloat(position.roe || 0);
      } else {
        const margin = parseFloat(position.margin_size || position.margin || 0);
        const pnl = parseFloat(position.unrealized_pnl || 0);

        if (margin > 0) {
          positionROE = (pnl / margin) * 100;
        }
      }

      totalROE += positionROE;
    });

    return totalROE;
  };

  const openROE = calculateOpenROE();

  if (loading) {
    return (
      <Paper sx={{ p: 2.5, height: 320 }}>
        <Typography variant="h6" sx={{ display: 'flex', alignItems: 'center', gap: 1, mb: 2, fontSize: '1.1rem' }}>
          📊 Estatísticas de Trading
        </Typography>
        <Box sx={{ display: 'flex', flexDirection: 'column', gap: 2 }}>
          <Skeleton variant="rectangular" height={60} />
          <Skeleton variant="rectangular" height={60} />
          <Skeleton variant="rectangular" height={60} />
        </Box>
      </Paper>
    );
  }

  return (
    <Paper sx={{ p: 2.5, height: 320, transition: 'all 0.3s ease-in-out' }}>
      {/* Cabeçalho */}
      <Typography variant="h6" sx={{ display: 'flex', alignItems: 'center', gap: 1, mb: 2, fontSize: '1.1rem' }}>
        📊 Estatísticas de Trading
      </Typography>

      {/* Conteúdo */}
      <Box sx={{ display: 'flex', flexDirection: 'column', gap: 2, height: 'calc(100% - 60px)' }}>

        {/* Lucro Realizado */}
        <Box sx={{ 
          display: 'flex', 
          alignItems: 'center', 
          justifyContent: 'space-between',
          p: 1.5,
          bgcolor: 'background.default',
          borderRadius: 1,
          border: `1px solid ${theme.palette.divider}`
        }}>
          <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
            <Timeline sx={{ color: getColorByValue(stats?.realized_pnl || 0), fontSize: 20 }} />
            <Typography variant="body1" sx={{ fontWeight: 500 }}>
              Lucro Realizado =
            </Typography>
          </Box>
          <Typography 
            variant="h6" 
            sx={{ 
              fontWeight: 'bold',
              color: getColorByValue(stats?.realized_pnl || 0)
            }}
          >
            {formatCurrency(stats?.realized_pnl)}
          </Typography>
        </Box>

        <Divider sx={{ my: 0.5 }} />

        {/* ROE Aberto */}
        <Box sx={{ 
          display: 'flex', 
          alignItems: 'center', 
          justifyContent: 'space-between',
          p: 1.5,
          bgcolor: 'background.default',
          borderRadius: 1,
          border: `1px solid ${theme.palette.divider}`
        }}>
          <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
            <ShowChart sx={{ color: getColorByValue(openROE || 0), fontSize: 20 }} />
            <Typography variant="body1" sx={{ fontWeight: 500 }}>
              ROE Aberto =
            </Typography>
          </Box>
          <Typography 
            variant="h6" 
            sx={{ 
              fontWeight: 'bold',
              color: getColorByValue(openROE || 0)
            }}
          >
            {formatPercentage(openROE)}
          </Typography>
        </Box>

        <Divider sx={{ my: 0.5 }} />

        {/* Taxa de Acerto */}
        <Box sx={{ 
          display: 'flex', 
          alignItems: 'center', 
          justifyContent: 'space-between',
          p: 1.5,
          bgcolor: 'background.default',
          borderRadius: 1,
          border: `1px solid ${theme.palette.divider}`
        }}>
          <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
            <TrendingUp sx={{ color: getColorByValue(stats?.win_rate || 0), fontSize: 20 }} />
            <Typography variant="body1" sx={{ fontWeight: 500 }}>
              Taxa de Acerto =
            </Typography>
          </Box>
          <Typography 
            variant="h6" 
            sx={{ 
              fontWeight: 'bold',
              color: getColorByValue(stats?.win_rate || 0)
            }}
          >
            {formatPercentage(stats?.win_rate)}
          </Typography>
        </Box>

        {/* Informação adicional */}
        <Box sx={{ mt: 'auto', pt: 1 }}>
          <Typography variant="caption" color="text.secondary" align="center" display="block">
            Atualizado automaticamente a cada 30 segundos
          </Typography>
        </Box>
      </Box>
    </Paper>
  );
};

export default ConsolidatedStatsCard;
